export const handler = (input) => {
  const ltvCaps = {
    real_estate: 0.75,
    equipment: 0.60,
    accounts_receivable: 0.80,
    inventory: 0.50,
    cash: 0.95
  };
  const cap = ltvCaps[input.collateral_type];
  if (cap === undefined) {
    return {
      within_threshold: false,
      max_ltv_pct: 0,
      breach_severity: 'unknown_collateral_type'
    };
  }
  if (input.collateral_value <= 0) {
    return {
      within_threshold: false,
      max_ltv_pct: cap,
      breach_severity: 'critical'
    };
  }
  const ltv = input.loan_amount / input.collateral_value;
  const within = ltv <= cap;
  let severity = 'none';
  if (!within) {
    const overage = ltv - cap;
    if (overage > 0.15) severity = 'critical';
    else if (overage > 0.05) severity = 'major';
    else severity = 'minor';
  }
  return {
    within_threshold: within,
    max_ltv_pct: cap,
    breach_severity: severity
  };
};
